+export function formatPrefetchStatusText(
+  status: PrefetchStatus,
+  includeContent = false,
+): string {
+  const lines = [
+    `Prefetch ${status.prefetchId}`,
+    `Provider: ${status.provider}`,
+    `Status: ${status.status}`,
+    `Ready: ${status.readyUrlCount}/${status.totalUrlCount}`,
+  ];
