+  for (const [index, entry] of status.urls.entries()) {
+    lines.push("");
+    lines.push(`${index + 1}. ${entry.url}`);
+    lines.push(`   ${entry.status}`);
+    if (entry.error) {
+      lines.push(`   ${entry.error}`);
+    }
+    if (includeContent && entry.text) {
+      for (const line of entry.text.split("\n")) {
+        lines.push(`   ${line}`);
+      }
+    }
+  }
+
+  return lines.join("\n");
+}
